-- ============================================================
-- FLIGHT_SCHEDULE (4 schedules)
-- Airline is derived via: Schedule → Aircraft → Airline
-- ============================================================
INSERT INTO public."FLIGHT_SCHEDULE" (
  schedule_id, aircraft_id,
  depart_airport_iata, dest_airport_iata,
  flight_number, depart_time, arrival_time,
  days_of_week, valid_from, valid_until
)
VALUES
  -- KE001: ICN → JFK (Korean Air, Mon/Wed/Fri, ~14h flight)
  ('00000000-0000-0000-0000-000000000501'::uuid,
   '00000000-0000-0000-0000-000000000301'::uuid,
   'ICN', 'JFK', 'KE001', '10:00', '10:00',
   'Mon,Wed,Fri', '2026-05-01', '2026-08-31'),

  -- DL100: JFK → LHR (Delta, Tue/Thu/Sat, ~7h flight)
  ('00000000-0000-0000-0000-000000000502'::uuid,
   '00000000-0000-0000-0000-000000000302'::uuid,
   'JFK', 'LHR', 'DL100', '19:00', '07:00',
   'Tue,Thu,Sat', '2026-05-01', '2026-08-31'),

  -- EK350: ICN → LHR via DXB (Emirates, Mon/Wed/Fri/Sun, ~18h total)
  ('00000000-0000-0000-0000-000000000503'::uuid,
   '00000000-0000-0000-0000-000000000303'::uuid,
   'ICN', 'LHR', 'EK350', '23:00', '17:00',
   'Mon,Wed,Fri,Sun', '2026-05-01', '2026-08-31'),

  -- KE621: SIN → ICN (Korean Air, daily, ~6h flight)
  ('00000000-0000-0000-0000-000000000504'::uuid,
   '00000000-0000-0000-0000-000000000301'::uuid,
   'SIN', 'ICN', 'KE621', '08:30', '16:30',
   'Mon,Tue,Wed,Thu,Fri,Sat,Sun', '2026-05-01', '2026-08-31')
ON CONFLICT (schedule_id) DO NOTHING;


-- ============================================================
-- STOPOVER (ICN → DXB → LHR route)
-- EK350 has a layover at DXB:
--   Depart ICN at 23:00
--   Arrive DXB after ~9h (+9:00), depart DXB after ~11h (+11:00)
--   Arrive LHR at 17:00 next day (+18:00 total)
-- ============================================================
INSERT INTO public."STOPOVER" (
  stopover_id, schedule_id, airport_iata,
  arrival_time_offset, departure_time_offset, stop_order
)
VALUES
  ('00000000-0000-0000-0000-000000000801'::uuid,
   '00000000-0000-0000-0000-000000000503'::uuid,
   'DXB',
   interval '9 hours',      -- arrives at DXB 9h after departure from ICN
   interval '11 hours',     -- departs DXB 11h after departure from ICN (2h layover)
   1)
ON CONFLICT (schedule_id, stop_order) DO NOTHING;


